@using sv_c6fc21a4b58b497cba711979d49a2da0.Services

<div class="sidebar-nav">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="nav-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.sidebar-nav {
    padding: 1rem 0;
}

.sidebar-title {
    padding: 0 1rem;
    margin-bottom: 1rem;
    font-weight: 600;
    color: var(--bs-secondary);
    text-transform: uppercase;
    font-size: 0.75rem;
    letter-spacing: 0.05em;
}

.sidebar-nav .nav-link {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.65rem 1rem;
    color: var(--bs-body-color);
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    border-radius: 0.375rem;
    margin: 0.125rem 0.5rem;
    font-size: 0.925rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.sidebar-nav .nav-link:hover {
    background-color: var(--bs-tertiary-bg);
}

.sidebar-nav .nav-link.active {
    background-color: var(--bs-primary);
    color: #fff;
    font-weight: 500;
}

.nav-icon {
    font-size: 1.1rem;
}

@using sv_c6fc21a4b58b497cba711979d49a2da0.Services

<div class="change-password-panel">
    <button class="btn btn-outline-secondary btn-sm" @onclick="ToggleExpanded">
        @(IsExpanded ? "▾" : "▸") Change Password
    </button>

    @if (IsExpanded)
    {
        <div class="password-form mt-3">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger py-2">@ErrorMessage</div>
            }

            @if (ShowSuccess)
            {
                <div class="alert alert-success py-2">Password updated successfully.</div>
            }

            <button class="btn btn-primary btn-sm" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @(IsSubmitting ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool IsExpanded;
    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private string? ErrorMessage;
    private bool IsSubmitting;
    private bool ShowSuccess;

    private void ToggleExpanded() => IsExpanded = !IsExpanded;

    private async Task HandleSubmit()
    {
        ErrorMessage = null;
        ShowSuccess = false;

        if (string.IsNullOrWhiteSpace(CurrentPassword) || string.IsNullOrWhiteSpace(NewPassword))
        {
            ErrorMessage = "All password fields are required.";
            return;
        }

        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "New password and confirmation do not match.";
            return;
        }

        if (NewPassword.Length < 8)
        {
            ErrorMessage = "New password must be at least 8 characters.";
            return;
        }

        IsSubmitting = true;
        try
        {
            await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
            ShowSuccess = true;
            CurrentPassword = "";
            NewPassword = "";
            ConfirmPassword = "";
        }
        catch (Exception ex)
        {
            ErrorMessage = ex.Message;
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

.change-password-panel {
    margin-bottom: 1.5rem;
}

.password-form {
    padding: 1rem;
    background: var(--bs-tertiary-bg);
    border-radius: 0.5rem;
    max-width: 400px;
}

.modal-backdrop-custom {
    display: none;
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.5);
    z-index: 1050;
    justify-content: center;
    align-items: center;
}

.modal-backdrop-custom.show {
    display: flex;
}

.modal-dialog-custom {
    width: 100%;
    max-width: 420px;
}

.modal-content {
    background: var(--bs-body-bg);
    border-radius: 0.5rem;
    box-shadow: 0 0.5rem 1rem rgba(0, 0, 0, 0.15);
}

.modal-header,
.modal-body,
.modal-footer {
    padding: 1rem 1.25rem;
}

.modal-footer {
    display: flex;
    justify-content: flex-end;
    gap: 0.5rem;
    border-top: 1px solid var(--bs-border-color);
}

.modal-header {
    border-bottom: 1px solid var(--bs-border-color);
}

