@using sv_c6fc21a4b58b497cba711979d49a2da0.Services

<div class="sidebar-nav">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="nav-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.sidebar-nav {
    padding: 1rem 0;
}

.sidebar-title {
    padding: 0 1rem;
    margin-bottom: 1rem;
    font-weight: 600;
    color: var(--bs-secondary);
    text-transform: uppercase;
    font-size: 0.75rem;
    letter-spacing: 0.05em;
}

.sidebar-nav .nav-link {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.65rem 1rem;
    color: var(--bs-body-color);
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    border-radius: 0.375rem;
    margin: 0.125rem 0.5rem;
    font-size: 0.925rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.sidebar-nav .nav-link:hover {
    background-color: var(--bs-tertiary-bg);
}

.sidebar-nav .nav-link.active {
    background-color: var(--bs-primary);
    color: #fff;
    font-weight: 500;
}

.nav-icon {
    font-size: 1.1rem;
}

