@using sv_c6fc21a4b58b497cba711979d49a2da0.Services

<div class="change-password-panel">
    <button class="btn btn-outline-secondary btn-sm" @onclick="ToggleExpanded">
        @(IsExpanded ? "▾" : "▸") Change Password
    </button>

    @if (IsExpanded)
    {
        <div class="password-form mt-3">
