                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger py-2">@ErrorMessage</div>
            }

            @if (ShowSuccess)
            {
                <div class="alert alert-success py-2">Password updated successfully.</div>
            }

            <button class="btn btn-primary btn-sm" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @(IsSubmitting ? "Updating…" : "Update Password")
            </button>
        </div>
