    <p class="text-muted">Manage your personal information.</p>

    @if (IsLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <span class="ms-2">Loading profile…</span>
        </div>
    }
    else if (Profile is not null)
    {
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="DisplayName" />
                </div>

                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="Email" />
                </div>

                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="3" @bind="Bio"></textarea>
                </div>
            </div>

            <div class="col-md-4">
                <div class="avatar-preview">
                    <img src="@AvatarUrl" alt="Avatar" class="avatar-img" />
                    <div class="avatar-url mt-2">
