        {
            <div class="alert @(IsError ? "alert-danger" : "alert-success") py-2 mt-2">@StatusMessage</div>
        }

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-primary" @onclick="SaveChanges" disabled="@IsSaving">
                @(IsSaving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges">Discard Changes</button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private UserProfile? Profile;
    private string DisplayName = "";
    private string Email = "";
    private string Bio = "";
    private string AvatarUrl = "";
    private bool IsLoading = true;
    private bool IsSaving;
    private string? StatusMessage;
    private bool IsError;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfile();
    }

    private async Task LoadProfile()
    {
        IsLoading = true;
        Profile = await SettingsService.GetProfileAsync();
        PopulateFields(Profile);
        IsLoading = false;
    }

    private void PopulateFields(UserProfile profile)
    {
        DisplayName = profile.DisplayName;
        Email = profile.Email;
        Bio = profile.Bio;
        AvatarUrl = profile.AvatarUrl;
    }

    private async Task SaveChanges()
    {
        StatusMessage = null;
        IsSaving = true;
        try
        {
            var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
            await SettingsService.SaveProfileAsync(updated);
            Profile = updated;
            StatusMessage = "Profile saved successfully!";
            IsError = false;
        }
        catch (Exception ex)
        {
            StatusMessage = $"Failed to save: {ex.Message}";
            IsError = true;
        }
        finally
        {
            IsSaving = false;
        }
    }

    private void DiscardChanges()
    {
        if (Profile is not null)
        {
            PopulateFields(Profile);
        }
        StatusMessage = null;
    }
}

