@using sv_c6fc21a4b58b497cba711979d49a2da0.Services

<div class="security-section">
    <h4>Security</h4>
    <p class="text-muted">Manage your account security and active sessions.</p>

    @if (IsLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <span class="ms-2">Loading security settings…</span>
        </div>
    }
    else if (Settings is not null)
    {
        <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

        <div class="tfa-section mb-4">
            <h6>Two-Factor Authentication</h6>
            <div class="d-flex align-items-center gap-3">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="tfa" checked="@TwoFactorEnabled" disabled />
                    <label class="form-check-label" for="tfa">
                        @(TwoFactorEnabled ? "Enabled" : "Disabled")
                    </label>
                </div>
                <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-warning text-dark")">
                    @(TwoFactorEnabled ? "✓ Active" : "⚠ Inactive")
                </span>
            </div>
            @if (Settings.LastPasswordChange.HasValue)
            {
                <p class="text-muted small mt-2 mb-0">
                    Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }
        </div>

        <div class="sessions-section">
            <h6>Active Sessions</h6>
            <div class="table-responsive">
                <table class="table table-sm table-hover">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (session != Sessions.FirstOrDefault())
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-info">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>

        <RevokeSessionDialog Visible="ShowRevokeDialog"
                             DeviceName="@(SessionToRevoke?.Device ?? "")"
                             IsProcessing="IsRevoking"
                             OnCancel="CancelRevoke"
                             OnConfirm="ConfirmRevoke" />
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private SecuritySettings? Settings;
    private List<ActiveSession> Sessions = new();
    private bool TwoFactorEnabled;
    private bool IsLoading = true;

    private ActiveSession? SessionToRevoke;
    private bool ShowRevokeDialog;
    private bool IsRevoking;

    protected override async Task OnInitializedAsync()
    {
        await LoadSettings();
    }

    private async Task LoadSettings()
    {
        IsLoading = true;
        Settings = await SettingsService.GetSecuritySettingsAsync();
        Sessions = Settings.Sessions;
        TwoFactorEnabled = Settings.TwoFactorEnabled;
        IsLoading = false;
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        await LoadSettings();
    }

    private void PromptRevoke(ActiveSession session)
    {
        SessionToRevoke = session;
        ShowRevokeDialog = true;
    }

    private void CancelRevoke()
    {
        ShowRevokeDialog = false;
        SessionToRevoke = null;
    }

    private async Task ConfirmRevoke()
    {
        if (SessionToRevoke is null) return;
        IsRevoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(SessionToRevoke.Id);
            await LoadSettings();
        }
        finally
        {
            IsRevoking = false;
            ShowRevokeDialog = false;
            SessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

.security-section h4 {
    margin-bottom: 0.25rem;
}

.tfa-section {
    padding: 1rem;
    background: var(--bs-tertiary-bg);
    border-radius: 0.5rem;
}

.sessions-section {
    margin-top: 0.5rem;
}

@using sv_c6fc21a4b58b497cba711979d49a2da0.Services

<div class="appearance-section">
    <h4>Appearance</h4>
    <p class="text-muted">Customize how the app looks and feels.</p>

    @if (IsLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <span class="ms-2">Loading appearance settings…</span>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-6">
                <div class="mb-4">
                    <h6>Theme</h6>
                    <div class="d-flex gap-3">
                        @foreach (var theme in Themes)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                                       value="@theme" checked="@(SelectedTheme == theme)"
                                       @onchange="() => SelectedTheme = theme" />
                                <label class="form-check-label" for="theme-@theme">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h6>Font Size</h6>
                    <div class="d-flex gap-3">
                        @foreach (var size in FontSizes)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                                       value="@size" checked="@(SelectedFontSize == size)"
                                       @onchange="() => SelectedFontSize = size" />
                                <label class="form-check-label" for="fs-@size">@size</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h6>Language</h6>
                    <select class="form-select" style="max-width: 240px;" @bind="SelectedLanguage">
                        @foreach (var lang in Languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <div class="mb-4">
                    <h6>Compact Mode</h6>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="CompactMode" />
                        <label class="form-check-label" for="compactMode">
                            @(CompactMode ? "On" : "Off")
                        </label>
                    </div>
                </div>

                @if (!string.IsNullOrEmpty(StatusMessage))
                {
                    <div class="alert alert-success py-2">@StatusMessage</div>
                }

                <button class="btn btn-primary" @onclick="SaveSettings" disabled="@IsSaving">
                    @(IsSaving ? "Saving…" : "Save")
                </button>
            </div>

            <div class="col-md-6">
                <h6>Preview</h6>
                <div class="live-preview @GetPreviewClasses()">
                    <div class="preview-header">
                        <strong>Sample Card</strong>
                    </div>
                    <div class="preview-body">
                        <p>This is how your content will look with the selected settings.</p>
                        <button class="preview-btn">Action Button</button>
                    </div>
                    <div class="preview-footer">
                        Theme: @SelectedTheme · Font: @SelectedFontSize · @SelectedLanguage
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private bool IsLoading = true;
    private bool IsSaving;
    private string? StatusMessage;

    private string SelectedTheme = "Light";
    private string SelectedFontSize = "Medium";
    private string SelectedLanguage = "English";
    private bool CompactMode;

    private static readonly string[] Themes = ["Light", "Dark", "System"];
    private static readonly string[] FontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        SelectedTheme = settings.Theme;
        SelectedFontSize = settings.FontSize;
        SelectedLanguage = settings.Language;
        CompactMode = settings.CompactMode;
        IsLoading = false;
    }

    private string GetPreviewClasses()
    {
        var theme = SelectedTheme.ToLowerInvariant();
        var fontSize = SelectedFontSize.ToLowerInvariant();
        var compact = CompactMode ? "compact" : "";
        return $"preview-{theme} preview-{fontSize} {compact}".Trim();
    }

    private async Task SaveSettings()
    {
        StatusMessage = null;
        IsSaving = true;
        try
        {
            var settings = new AppearanceSettings(SelectedTheme, SelectedFontSize, SelectedLanguage, CompactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            StatusMessage = "Appearance settings saved!";
        }
        finally
        {
            IsSaving = false;
        }
    }
}

.appearance-section h4 {
    margin-bottom: 0.25rem;
}

/* Live Preview */
.live-preview {
    border: 1px solid var(--bs-border-color);
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.2s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid var(--bs-border-color);
}

.preview-body {
    padding: 1rem;
}

.preview-body p {
    margin-bottom: 0.75rem;
}

.preview-btn {
    padding: 0.375rem 0.75rem;
    border: none;
    border-radius: 0.25rem;
    cursor: pointer;
    font-size: inherit;
}

.preview-footer {
    padding: 0.5rem 1rem;
    font-size: 0.75rem;
    border-top: 1px solid var(--bs-border-color);
}

/* Theme variants */
.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-light .preview-header {
    background: #f8f9fa;
}

.preview-light .preview-footer {
    background: #f8f9fa;
    color: #6c757d;
}

.preview-light .preview-btn {
    background: #0d6efd;
    color: #fff;
}

.preview-dark {
    background: #1a1d21;
    color: #dee2e6;
}

.preview-dark .preview-header {
    background: #2b3035;
    border-color: #495057;
}

.preview-dark .preview-body {
    border-color: #495057;
}

.preview-dark .preview-footer {
    background: #2b3035;
    color: #adb5bd;
    border-color: #495057;
}

.preview-dark .preview-btn {
    background: #0d6efd;
    color: #fff;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1a1d21 50%);
    color: #212529;
}

.preview-system .preview-header {
    background: rgba(248, 249, 250, 0.85);
}

.preview-system .preview-footer {
    background: rgba(248, 249, 250, 0.85);
    color: #6c757d;
}

.preview-system .preview-btn {
    background: #0d6efd;
    color: #fff;
}

/* Font size variants */
.preview-small {
    font-size: 0.8rem;
}

.preview-medium {
    font-size: 1rem;
}

.preview-large {
    font-size: 1.2rem;
}

/* Compact mode */
::deep .live-preview.compact .preview-header {
    padding: 0.4rem 0.75rem;
}

::deep .live-preview.compact .preview-body {
    padding: 0.5rem 0.75rem;
}

::deep .live-preview.compact .preview-footer {
    padding: 0.25rem 0.75rem;
}

::deep .live-preview.compact .preview-body p {
    margin-bottom: 0.35rem;
}

