<div class="security-section">
    <h4>Security</h4>
    <p class="text-muted">Manage your account security and active sessions.</p>

    @if (IsLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <span class="ms-2">Loading security settings…</span>
        </div>
    }
    else if (Settings is not null)
    {
        <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

        <div class="tfa-section mb-4">
            <h6>Two-Factor Authentication</h6>
            <div class="d-flex align-items-center gap-3">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="tfa" checked="@TwoFactorEnabled" disabled />
                    <label class="form-check-label" for="tfa">
                        @(TwoFactorEnabled ? "Enabled" : "Disabled")
                    </label>
                </div>
                <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-warning text-dark")">
                    @(TwoFactorEnabled ? "✓ Active" : "⚠ Inactive")
                </span>
            </div>
            @if (Settings.LastPasswordChange.HasValue)
            {
                <p class="text-muted small mt-2 mb-0">
                    Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }
        </div>

        <div class="sessions-section">
            <h6>Active Sessions</h6>
            <div class="table-responsive">
                <table class="table table-sm table-hover">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (session != Sessions.FirstOrDefault())
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-info">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>

        <RevokeSessionDialog Visible="ShowRevokeDialog"
                             DeviceName="@(SessionToRevoke?.Device ?? "")"
                             IsProcessing="IsRevoking"
                             OnCancel="CancelRevoke"
                             OnConfirm="ConfirmRevoke" />
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private SecuritySettings? Settings;
    private List<ActiveSession> Sessions = new();
    private bool TwoFactorEnabled;
    private bool IsLoading = true;

    private ActiveSession? SessionToRevoke;
    private bool ShowRevokeDialog;
    private bool IsRevoking;

    protected override async Task OnInitializedAsync()
    {
        await LoadSettings();
    }

    private async Task LoadSettings()
    {
        IsLoading = true;
        Settings = await SettingsService.GetSecuritySettingsAsync();
        Sessions = Settings.Sessions;
        TwoFactorEnabled = Settings.TwoFactorEnabled;
        IsLoading = false;
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        await LoadSettings();
    }

    private void PromptRevoke(ActiveSession session)
    {
        SessionToRevoke = session;
        ShowRevokeDialog = true;
    }

    private void CancelRevoke()
    {
        ShowRevokeDialog = false;
        SessionToRevoke = null;
    }

    private async Task ConfirmRevoke()
    {
        if (SessionToRevoke is null) return;
        IsRevoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(SessionToRevoke.Id);
            await LoadSettings();
        }
        finally
        {
            IsRevoking = false;
            ShowRevokeDialog = false;
            SessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}
