{"file_text": "@using sv_c6fc21a4b58b497cba711979d49a2da0.Services

<div class="appearance-section">
    <h4>Appearance</h4>
    <p class="text-muted">Customize how the app looks and feels.</p>

    @if (IsLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <span class="ms-2">Loading appearance settings…</span>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-6">
                <div class="mb-4">
                    <h6>Theme</h6>
                    <div class="d-flex gap-3">
                        @foreach (var theme in Themes)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                                       value="@theme" checked="@(SelectedTheme == theme)"
                                       @onchange="() => SelectedTheme = theme" />
                                <label class="form-check-label" for="theme-@theme">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h6>Font Size</h6>
                    <div class="d-flex gap-3">
                        @foreach (var size in FontSizes)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                                       value="@size" checked="@(SelectedFontSize == size)"
                                       @onchange="() => SelectedFontSize = size" />
                                <label class="form-check-label" for="fs-@size">@size</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h6>Language</h6>
                    <select class="form-select" style="max-width: 240px;" @bind="SelectedLanguage">
                        @foreach (var lang in Languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <div class="mb-4">
                    <h6>Compact Mode</h6>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="CompactMode" />
                        <label class="form-check-label" for="compactMode">
                            @(CompactMode ? "On" : "Off")
                        </label>
                    </div>
                </div>

                @if (!string.IsNullOrEmpty(StatusMessage))
                {
                    <div class="alert alert-success py-2">@StatusMessage</div>
                }

                <button class="btn btn-primary" @onclick="SaveSettings" disabled="@IsSaving">
                    @(IsSaving ? "Saving…" : "Save")
                </button>
            </div>

            <div class="col-md-6">
                <h6>Preview</h6>
                <div class="live-preview @GetPreviewClasses()">
                    <div class="preview-header">
                        <strong>Sample Card</strong>
                    </div>
                    <div class="preview-body">
                        <p>This is how your content will look with the selected settings.</p>
                        <button class="preview-btn">Action Button</button>
                    </div>
                    <div class="preview-footer">
                        Theme: @SelectedTheme · Font: @SelectedFontSize · @SelectedLanguage
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private bool IsLoading = true;
    private bool IsSaving;
    private string? StatusMessage;

    private string SelectedTheme = "Light";
    private string SelectedFontSize = "Medium";
    private string SelectedLanguage = "English";
    private bool CompactMode;

    private static readonly string[] Themes = ["Light", "Dark", "System"];
    private static readonly string[] FontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        SelectedTheme = settings.Theme;
        SelectedFontSize = settings.FontSize;
        SelectedLanguage = settings.Language;
        CompactMode = settings.CompactMode;
        IsLoading = false;
    }

    private string GetPreviewClasses()
    {
        var theme = SelectedTheme.ToLowerInvariant();
        var fontSize = SelectedFontSize.ToLowerInvariant();
        var compact = CompactMode ? "compact" : "";
        return $"preview-{theme} preview-{fontSize} {compact}".Trim();
    }

    private async Task SaveSettings()
    {
        StatusMessage = null;
        IsSaving = true;
        try
        {
            var settings = new AppearanceSettings(SelectedTheme, SelectedFontSize, SelectedLanguage, CompactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            StatusMessage = "Appearance settings saved!";
        }
        finally
        {
            IsSaving = false;
        }
    }
}
