.appearance-section h4 {
    margin-bottom: 0.25rem;
}

/* Live Preview */
.live-preview {
    border: 1px solid var(--bs-border-color);
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.2s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid var(--bs-border-color);
}

.preview-body {
    padding: 1rem;
}

.preview-body p {
    margin-bottom: 0.75rem;
}

.preview-btn {
    padding: 0.375rem 0.75rem;
    border: none;
    border-radius: 0.25rem;
    cursor: pointer;
    font-size: inherit;
}

.preview-footer {
    padding: 0.5rem 1rem;
    font-size: 0.75rem;
    border-top: 1px solid var(--bs-border-color);
}

/* Theme variants */
.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-light .preview-header {
    background: #f8f9fa;
}

.preview-light .preview-footer {
    background: #f8f9fa;
    color: #6c757d;
}

.preview-light .preview-btn {
    background: #0d6efd;
    color: #fff;
}

.preview-dark {
    background: #1a1d21;
    color: #dee2e6;
}

.preview-dark .preview-header {
    background: #2b3035;
    border-color: #495057;
}

.preview-dark .preview-body {
    border-color: #495057;
}

.preview-dark .preview-footer {
    background: #2b3035;
    color: #adb5bd;
    border-color: #495057;
}

.preview-dark .preview-btn {
    background: #0d6efd;
    color: #fff;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1a1d21 50%);
    color: #212529;
}

.preview-system .preview-header {
    background: rgba(248, 249, 250, 0.85);
}

.preview-system .preview-footer {
    background: rgba(248, 249, 250, 0.85);
    color: #6c757d;
}

.preview-system .preview-btn {
    background: #0d6efd;
    color: #fff;
}

/* Font size variants */
.preview-small {
    font-size: 0.8rem;
}

.preview-medium {
    font-size: 1rem;
}

.preview-large {
    font-size: 1.2rem;
}

/* Compact mode */
::deep .live-preview.compact .preview-header {
    padding: 0.4rem 0.75rem;
}

::deep .live-preview.compact .preview-body {
    padding: 0.5rem 0.75rem;
}

::deep .live-preview.compact .preview-footer {
    padding: 0.25rem 0.75rem;
}

::deep .live-preview.compact .preview-body p {
    margin-bottom: 0.35rem;
}

