@page "/settings"
@using sv_c6fc21a4b58b497cba711979d49a2da0.Services
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <aside class="settings-sidebar">
        <SettingsSidebar ActiveSection="@ActiveSection" OnSectionChanged="SetActiveSection" />
    </aside>

    <main class="settings-content">
        @switch (ActiveSection)
        {
            case "Profile":
                <ProfileSection SettingsService="SettingsService" />
                break;
            case "Notifications":
                <NotificationsSection SettingsService="SettingsService" />
                break;
            case "Security":
                <SecuritySection SettingsService="SettingsService" />
                break;
            case "Appearance":
                <AppearanceSection SettingsService="SettingsService" />
                break;
        }
    </main>
</div>

@code {
    private string ActiveSection = "Profile";

    private void SetActiveSection(string section)
    {
        ActiveSection = section;
    }
}

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 4rem);
    gap: 0;
}

.settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    border-right: 1px solid var(--bs-border-color);
    background: var(--bs-tertiary-bg);
}

.settings-content {
    flex: 1;
    padding: 1.5rem 2rem;
    max-width: 900px;
}

